import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Premium basics — single item, no modifiers
  it("empty item list yields premium of 5 G (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("single plain sword (no modifiers) yields premium of 105 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 105 }] });
  });
  it.todo("single plain amulet yields premium of 65 G");
  it.todo("single plain staff yields premium of 85 G");
  it.todo("single plain potion yields premium of 45 G");

  // Multiple main items
  it.todo("sword + amulet yields premium of 165 G (100+60+5)");

  // Components and building blocks
  it.todo("2 runes yields premium of 55 G (50 base + 5 fee)");
  it.todo("3 runes yields premium of 65 G (60 block + 5 fee)");
  it.todo("4 runes yields premium of 105 G (100 base + 5 fee)");
  it.todo("7 runes yields premium of 180 G (175 base + 5 fee)");
  it.todo("2 runes + 1 moonstone yields premium of 80 G (75 + 5)");
  it.todo("3 runes + 3 moonstones yields premium of 125 G (60+60+5)");

  // Item-specific modifiers
  it.todo("cursed sword applies 50% surcharge to sword's base premium");
  it.todo("sword with enchantment 5 applies 30% high-enchantment surcharge");
  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 applies both surcharges");
  it.todo("cursed sword + plain amulet: surcharge only on sword (210 G before fee)");

  // Policy-wide modifiers
  it.todo("customer with 2 years gets 20% loyalty discount");
  it.todo("customer with 1 year gets no loyalty discount");
  it.todo("first quote in scenario adds 10% first-insurance surcharge per item");
  it.todo("second quote in scenario gets 15% follow-up contract discount");

  // Integration examples from prompt
  it.todo("newcomer with cursed sword: premium 165 G");
  it.todo("long-standing customer second contract with cursed enchanted sword: 160 G");

  // Rounding
  it.todo("premium calculation rounds up in MHPCO's favor");

  // Claim basics
  it.todo("claim on plain sword: full reimbursement minus 100 G deductible");
  it.todo("claim on rune (no enchantment/material): full reimbursement minus deductible");
  it.todo("claim on enchantment-8 dragon sword damage 1000: payout 400 (50% then deductible)");
  it.todo("claim on dragon-material sword enchantment 5 damage 800: payout 700 (full minus deductible)");
  it.todo("claim on steel sword enchantment 9 damage 1000: payout 400 (50% then deductible)");
  it.todo("dragon attack on sword (500) + amulet (300): payout 600 (deductible per item)");

  // Cap
  it.todo("two successive 1500 G claims on sword: 1400 then 600 (cap exhaustion)");
  it.todo("remainingCap reflects cap consumed by payouts");

  // Multi-item-of-same-type
  it.todo("policy with two swords: insurance sum 2000, cap 4000");
  it.todo("more damages of a type than insured items: CLI rejects claim");

  // Rounding for payouts
  it.todo("payout calculation rounds down in MHPCO's favor");

  // Validation errors
  it.todo("unknown item type in quote: CLI exits non-zero with stderr error");
  it.todo("claim references damage to item not in policy: CLI exits non-zero");
  it.todo("claim with negative damage amount: CLI exits non-zero");
});

