const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const quotePremium = (items: Item[]): number => {
  const base = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
  const firstInsurance = base * FIRST_INSURANCE_RATE;
  return base + firstInsurance + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => ({
  results: scenario.steps.map((step) => ({ premium: quotePremium(step.items) })),
});

