const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const COMPONENT_BASE = 25;
const COMPONENT_BLOCK_BASE = 60;
const BLOCK_SIZE = 3;

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

const isComponent = (item: Item) => COMPONENT_TYPES.has(item.type);

const componentBase = (items: Item[]): number => {
  const counts: Record<string, number> = {};
  for (const item of items) counts[item.type] = (counts[item.type] ?? 0) + 1;
  let total = 0;
  for (const count of Object.values(counts)) {
    const blocks = Math.floor(count / BLOCK_SIZE);
    const remainder = count % BLOCK_SIZE;
    total += blocks * COMPONENT_BLOCK_BASE + remainder * COMPONENT_BASE;
  }
  return total;
};

const quotePremium = (items: Item[]): number => {
  const components = items.filter(isComponent);
  const mains = items.filter((i) => !isComponent(i));
  const base = mains.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0) + componentBase(components);
  const firstInsurance = base * FIRST_INSURANCE_RATE;
  return base + firstInsurance + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => ({
  results: scenario.steps.map((step) => ({ premium: quotePremium(step.items) })),
});

