  it.todo("claim on rune (no enchantment/material): full reimbursement minus deductible");
  it.todo("claim on enchantment-8 dragon sword damage 1000: payout 400 (50% then deductible)");
  it.todo("claim on dragon-material sword enchantment 5 damage 800: payout 700 (full minus deductible)");
  it.todo("claim on steel sword enchantment 9 damage 1000: payout 400 (50% then deductible)");
  it.todo("dragon attack on sword (500) + amulet (300): payout 600 (deductible per item)");

  // Cap
  it.todo("two successive 1500 G claims on sword: 1400 then 600 (cap exhaustion)");
  it.todo("remainingCap reflects cap consumed by payouts");

  // Multi-item-of-same-type
  it.todo("policy with two swords: insurance sum 2000, cap 4000");
  it.todo("more damages of a type than insured items: CLI rejects claim");

  // Rounding for payouts
  it.todo("payout calculation rounds down in MHPCO's favor");

  // Validation errors
  it.todo("unknown item type in quote: CLI exits non-zero with stderr error");
  it.todo("claim references damage to item not in policy: CLI exits non-zero");
  it.todo("claim with negative damage amount: CLI exits non-zero");
});

