const itemSurcharge = (item: Item): number => {
  const base = itemBase(item);
  let surcharge = 0;
  if (item.cursed) surcharge += base * CURSE_RATE;
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) surcharge += base * HIGH_ENCHANTMENT_RATE;
  return surcharge;
};

const quotePremium = (items: Item[]): number => {
  const components = items.filter(isComponent);
  const mains = items.filter((i) => !isComponent(i));
  const policyBase = mains.reduce((sum, item) => sum + itemBase(item), 0) + componentBase(components);
  const itemSurcharges = mains.reduce((sum, item) => sum + itemSurcharge(item), 0);
  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
  return Math.ceil(policyBase + itemSurcharges + firstInsurance + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => ({
  results: scenario.steps.map((step) => ({ premium: quotePremium(step.items) })),
});

