  if (unknownType !== undefined) fail(`Unknown item type: ${unknownType}`);

  const uninsured = findUninsuredDamage(scenario);
  if (uninsured) fail(`Damage references item not in policy: ${uninsured.itemType}`);

  process.stdout.write(JSON.stringify(runScenario(scenario)) + "\n");
};

